                  sheetController.captainA = ((captainList.keys.toList().contains(selectedCaptainA.value)) ? captainList[selectedCaptainA.value] : "") ?? "";
                  sheetController.captainBID = selectedCaptainB.value;
                  sheetController.captainB = ((captainList.keys.toList().contains(selectedCaptainB.value)) ? captainList[selectedCaptainB.value] : "") ?? "";
