  add("asslide-4", "flutter", "foursome_bet_bottom_controller.dart", `
import 'package:flutter/material.dart';
import 'package:get/get.dart';

import '../../apis/api_services.dart';
import '../../model/game_models/calcutta_foursome_model.dart';
import '../../model/game_models/get_foursome_override_model.dart';
import '../../utils/show_progress_dialog.dart';
import '../../utils/toast_message.dart';

class FoursomeBetBottomController extends GetxController {
  var betPerMatchController = TextEditingController(text: "3");
  var totalSkinPotController = TextEditingController(text: "150");
  var totalGreeniePotController = TextEditingController(text: "150");
  var perDotController = TextEditingController(text: "0.50");
  var skodePoolController = TextEditingController(text: "5");
  var junkPoolController = TextEditingController(text: "5");
  var amountPerPoint = TextEditingController(text: "0.10");
  GlobalKey<FormState> formStateKey = GlobalKey<FormState>();

  RxList<CalcuttaPlayers> players = <CalcuttaPlayers>[].obs;
  GlobalKey<FormState> formKey1 = GlobalKey<FormState>();

  var apiService = ApiServices();
  var progressDialog = ShowProgressDialog();
  String gameId = '';
  String foursomeId = '';
  String foursomeNo = '';
  String organizationId = '';
  String gameType = '';
  String playType = '';
  RxBool isRabbitChicken = false.obs;
  RxBool isAutoSKodeJunk = false.obs;
  RxBool isDots = false.obs;
  RxBool isSkins = false.obs;
  RxBool isGreenie = false.obs;
  RxBool isPlayerRestrict = true.obs;
  RxBool isBasement = false.obs;
  RxBool isEditable = false.obs;
  RxString selectedPlayerId = "".obs;

  Rx<OverrideData> overrideData = OverrideData().obs;

  @override
  void onReady() {
    // setDefaultPlayer();
    super.onReady();
  }

  Future<void> getFoursomeOverride() async {
    try {
      progressDialog.show();
      var response = await apiService.getFoursomeOverride(
          gameID: gameId,
          foursomeId: foursomeId,
          organizationId: organizationId);
      progressDialog.hide();
      if (response.error == false) {
        // Helper function to remove trailing .00
        String formatNumber(String? value, {String defaultValue = "0"}) {
          if (value == null || value.isEmpty) return defaultValue;
          double? num = double.tryParse(value);
          if (num == null) return defaultValue;
          if (num % 1 == 0) return num.toInt().toString(); // whole number
          return num.toString(); // keep decimal if not whole
        }

        overrideData.value = response.data!;
        betPerMatchController.text = overrideData.value.betPerMatch ?? "3";
        amountPerPoint.text = overrideData.value.amountPerPoint ??
            (gameType == "3_2_1" ? "1" : "0.10");
        skodePoolController.text =
            formatNumber(overrideData.value.skodePoolPrize, defaultValue: "5");
        junkPoolController.text =
            formatNumber(overrideData.value.junkPoolPrize, defaultValue: "5");
        isBasement.value = overrideData.value.isBasementVegas!;
        isRabbitChicken.value = overrideData.value.enableRabbitChickenBet!;
        isDots.value = overrideData.value.isDotsEnabled!;
        isAutoSKodeJunk.value = overrideData.value.isAutoNewtTwoferEnabled!;
        selectedPlayerId.value = overrideData.value.scorekeeperId ?? '';
        isPlayerRestrict.value =
            overrideData.value.scoreEditPolicy == "scorekeeper_only"
                ? true
                : false;
        totalGreeniePotController.text=(overrideData.value.greeniePool=="0.00"?"150":overrideData.value.greeniePool)!;
        totalSkinPotController.text=(overrideData.value.skinPool=="0.00"?"150":overrideData.value.skinPool)!;
        isSkins.value=overrideData.value.isSkinGameEnabled!;
        isGreenie.value=overrideData.value.isGreenieGameEnabled!;
        if (selectedPlayerId.value.isEmpty) {
          setDefaultPlayer();
        }
        print("score keeper => ${selectedPlayerId.value}");
        print("isDots.value => ${isDots.value}");
        print(
            "overrideData.value.isDotsEnabled => ${overrideData.value.isDotsEnabled!}");
      } else {
        ToastMessage.error(message: response.message);
      }
    } catch (error) {
      progressDialog.hide();
      debugPrint("getGameDetails : $error");
      ToastMessage.error(message: error.toString());
    }
  }

  void getPlayerData() {
    for (int i = 0; i < players.length; i++) {
      print("player name => ${players[i].name}");
      print("player id => ${players[i].playerId}");
    }
  }

  void setDefaultPlayer() {
    if (players.isNotEmpty && selectedPlayerId.isEmpty) {
      selectedPlayerId.value = players.first.playerId!;
      debugPrint("Default player set: ${selectedPlayerId.value}");
      debugPrint("Default player set ID: ${selectedPlayerId.value}");
      // ADD THIS:
      for (var p in players) {
        debugPrint(
            "Player => id: '${p.playerId}' | name: '${p.name}' | idType: ${p.playerId.runtimeType}");
      }
    }
  }

  Future<void> getTeeSheetGroup(
      {bool progress = true, bool isGenerateMatch = false}) async {
    try {
      progressDialog.show();
      var response = await apiService.getFourSomePlayer(foursomeId);
      players.clear();
      progressDialog.hide();
      if (response.data != null) {
        players.addAll(response.data!.map((playerData) => CalcuttaPlayers(
            name: playerData.name, playerId: playerData.playerId.toString())));
        setDefaultPlayer();
        update();
      } else {
        progressDialog.hide();
        debugPrint('Error msg: $response');
      }
    } catch (error) {
      progressDialog.hide();
      ToastMessage.error(message: "$error");
      debugPrint('Error fetching leaderboard: $error');
    }
  }
}
`);
